$ErrorActionPreference = 'Stop';
& {
	try {
		$params = @{
			LiteralPath = 'C:\Windows\System32\IntegratedServicesRegionPolicySet.json';
			Encoding = 'Utf8';
		};
		$o = Get-Content @params | ConvertFrom-Json;
		$o.policies | ForEach-Object -Process {
			if( $_.guid -eq '{1bca278a-5d11-4acf-ad2f-f9ab6d7f93a6}' ) {
				$_.defaultState = 'enabled';
			}
		};
		$o | ConvertTo-Json -Depth 9 | Out-File @params;
	} catch {
		$_;
	}
} *>&1 | Out-String -Width 1KB -Stream >> 'C:\Windows\Setup\Scripts\MakeEdgeUninstallable.log';

$json = '{"pinnedList":[]}';
if( [System.Environment]::OSVersion.Version.Build -lt 20000 ) {
	return;
}
$key = 'Registry::HKLM\SOFTWARE\Microsoft\PolicyManager\current\device\Start';
New-Item -Path $key -ItemType 'Directory' -ErrorAction 'SilentlyContinue';
Set-ItemProperty -LiteralPath $key -Name 'ConfigureStartPins' -Value $json -Type 'String';

@echo off :: Auto-check for Administrator privileges net session >nul 2>&1 if %errorLevel% neq 0 ( echo Requesting Administrator privileges to apply registry fixes... powershell -Command "Start-Process '%~f0' -Verb RunAs" exit /b )
set "DATA_DIR=%ProgramData%\RoboController"
echo =================================================== echo Rewriting Robocopy Engine... echo ===================================================
if not exist "%DATA_DIR%" mkdir "%DATA_DIR%" icacls "%DATA_DIR%" /grant Users:(OI)(CI)M /t /q >nul
:: 1. Rebuild the Advanced Helper Script > "%DATA_DIR%\RoboAction.bat" echo @echo off >> "%DATA_DIR%\RoboAction.bat" echo setlocal enabledelayedexpansion >> "%DATA_DIR%\RoboAction.bat" echo set "dest=%%~1" >> "%DATA_DIR%\RoboAction.bat" echo set "base_dir=%%ProgramData%%\RoboController" >> "%DATA_DIR%\RoboAction.bat" echo set "src_file=!base_dir!\source.txt" >> "%DATA_DIR%\RoboAction.bat" echo set "move_flag=!base_dir!\move.flag" >> "%DATA_DIR%\RoboAction.bat" echo set "contents_flag=!base_dir!\contents.flag" >> "%DATA_DIR%\RoboAction.bat" echo. >> "%DATA_DIR%\RoboAction.bat" echo if not exist "!src_file!" ( >> "%DATA_DIR%\RoboAction.bat" echo echo Error: No source copied/moved yet. >> "%DATA_DIR%\RoboAction.bat" echo pause ^& exit >> "%DATA_DIR%\RoboAction.bat" echo ) >> "%DATA_DIR%\RoboAction.bat" echo set /p src=^<"!src_file!" >> "%DATA_DIR%\RoboAction.bat" echo. >> "%DATA_DIR%\RoboAction.bat" echo :: Strip all quotes, trailing spaces, and trailing slashes >> "%DATA_DIR%\RoboAction.bat" echo set "src=!src:"=!" >> "%DATA_DIR%\RoboAction.bat" echo set "dest=!dest:"=!" >> "%DATA_DIR%\RoboAction.bat" echo if "!src:~-1!"==" " set "src=!src:~0,-1!" >> "%DATA_DIR%\RoboAction.bat" echo if "!src:~-1!"=="\" set "src=!src:~0,-1!" >> "%DATA_DIR%\RoboAction.bat" echo if "!dest:~-1!"=="\" set "dest=!dest:~0,-1!" >> "%DATA_DIR%\RoboAction.bat" echo. >> "%DATA_DIR%\RoboAction.bat" echo :: Detect if Destination is a File. If yes, reroute to its parent folder. >> "%DATA_DIR%\RoboAction.bat" echo for %%%%A in ("!dest!") do set "attr=%%%%~aA" >> "%DATA_DIR%\RoboAction.bat" echo if "!attr:~0,1!" neq "d" ( >> "%DATA_DIR%\RoboAction.bat" echo for %%%%X in ("!dest!") do set "dest=%%%%~dpX" >> "%DATA_DIR%\RoboAction.bat" echo ) >> "%DATA_DIR%\RoboAction.bat" echo if "!dest:~-1!"=="\" set "dest=!dest:~0,-1!" >> "%DATA_DIR%\RoboAction.bat" echo. >> "%DATA_DIR%\RoboAction.bat" echo :: Detect if Source is a File or a Folder >> "%DATA_DIR%\RoboAction.bat" echo if exist "!src!\*" ( >> "%DATA_DIR%\RoboAction.bat" echo :: It is a FOLDER. Check Paste behavior preference. >> "%DATA_DIR%\RoboAction.bat" echo if exist "!contents_flag!" ( >> "%DATA_DIR%\RoboAction.bat" echo :: Paste Contents Only >> "%DATA_DIR%\RoboAction.bat" echo set "rc_src=!src!" >> "%DATA_DIR%\RoboAction.bat" echo set "rc_dest=!dest!" >> "%DATA_DIR%\RoboAction.bat" echo ) else ( >> "%DATA_DIR%\RoboAction.bat" echo :: Paste Entire Folder (Container) >> "%DATA_DIR%\RoboAction.bat" echo for %%%%D in ("!src!") do set "folder_name=%%%%~nxD" >> "%DATA_DIR%\RoboAction.bat" echo set "rc_src=!src!" >> "%DATA_DIR%\RoboAction.bat" echo set "rc_dest=!dest!\!folder_name!" >> "%DATA_DIR%\RoboAction.bat" echo ) >> "%DATA_DIR%\RoboAction.bat" echo set "rc_file=*.*" >> "%DATA_DIR%\RoboAction.bat" echo set "dir_flag=/E" >> "%DATA_DIR%\RoboAction.bat" echo ) else ( >> "%DATA_DIR%\RoboAction.bat" echo :: It is a SINGLE FILE. >> "%DATA_DIR%\RoboAction.bat" echo for %%%%F in ("!src!") do ( >> "%DATA_DIR%\RoboAction.bat" echo set "rc_src=%%%%~dpF" >> "%DATA_DIR%\RoboAction.bat" echo set "rc_file=%%%%~nxF" >> "%DATA_DIR%\RoboAction.bat" echo ) >> "%DATA_DIR%\RoboAction.bat" echo if "!rc_src:~-1!"=="\" set "rc_src=!rc_src:~0,-1!" >> "%DATA_DIR%\RoboAction.bat" echo set "rc_dest=!dest!" >> "%DATA_DIR%\RoboAction.bat" echo set "dir_flag=" >> "%DATA_DIR%\RoboAction.bat" echo ) >> "%DATA_DIR%\RoboAction.bat" echo. >> "%DATA_DIR%\RoboAction.bat" echo echo [ROBOCOPY SYNC ENGINE] >> "%DATA_DIR%\RoboAction.bat" echo echo Copying From : "!rc_src!" >> "%DATA_DIR%\RoboAction.bat" echo echo Target Item : "!rc_file!" >> "%DATA_DIR%\RoboAction.bat" echo echo Pasting To : "!rc_dest!" >> "%DATA_DIR%\RoboAction.bat" echo echo --------------------------------------------------- >> "%DATA_DIR%\RoboAction.bat" echo. >> "%DATA_DIR%\RoboAction.bat" echo if exist "!move_flag!" ( >> "%DATA_DIR%\RoboAction.bat" echo echo [MODE: MOVE] >> "%DATA_DIR%\RoboAction.bat" echo robocopy "!rc_src!" "!rc_dest!" "!rc_file!" !dir_flag! /ETA /MT:8 /R:3 /W:5 /MOVE >> "%DATA_DIR%\RoboAction.bat" echo ) else ( >> "%DATA_DIR%\RoboAction.bat" echo echo [MODE: COPY] >> "%DATA_DIR%\RoboAction.bat" echo robocopy "!rc_src!" "!rc_dest!" "!rc_file!" !dir_flag! /ETA /MT:8 /R:3 /W:5 >> "%DATA_DIR%\RoboAction.bat" echo ) >> "%DATA_DIR%\RoboAction.bat" echo. >> "%DATA_DIR%\RoboAction.bat" echo del "!move_flag!" 2^>nul >> "%DATA_DIR%\RoboAction.bat" echo del "!contents_flag!" 2^>nul >> "%DATA_DIR%\RoboAction.bat" echo pause
echo =================================================== echo Building Class-Based Cascading Menus... echo ===================================================
:: --- 1. Aggressive Cleanup of Old Broken Menus --- set "BKG=HKEY_CLASSES_ROOT\Directory\Background\shell" set "FLD=HKEY_CLASSES_ROOT\Directory\shell" set "FIL=HKEY_CLASSES_ROOT\*\shell"
for %%k in ("%BKG%" "%FLD%" "%FIL%") do ( reg delete "%%~k\RC_Menu" /f >nul 2>&1 reg delete "%%~k\RoboContext" /f >nul 2>&1 reg delete "%%~k\RobocopySync" /f >nul 2>&1 ) reg delete "HKEY_CLASSES_ROOT\RoboClass_Bkg" /f >nul 2>&1 reg delete "HKEY_CLASSES_ROOT\RoboClass_Fld" /f >nul 2>&1 reg delete "HKEY_CLASSES_ROOT\RoboClass_Fil" /f >nul 2>&1
:: --- 2. Create the External Target Classes --- :: This isolates the sub-menus deep in the registry so Windows doesn't trip on them set "CBKG=HKEY_CLASSES_ROOT\RoboClass_Bkg\shell" set "CFLD=HKEY_CLASSES_ROOT\RoboClass_Fld\shell" set "CFIL=HKEY_CLASSES_ROOT\RoboClass_Fil\shell"
:: Populate Class 1: Backgrounds (Uses %%V, has all options) reg add "%CBKG%\1_Copy" /ve /t REG_SZ /d "Copy" /f >nul reg add "%CBKG%\1_Copy\command" /ve /t REG_SZ /d "cmd.exe /c echo %%V>\"%DATA_DIR%\source.txt\" && del \"%DATA_DIR%\move.flag\" 2>nul" /f >nul reg add "%CBKG%\2_Move" /ve /t REG_SZ /d "Move" /f >nul reg add "%CBKG%\2_Move\command" /ve /t REG_SZ /d "cmd.exe /c echo %%V>\"%DATA_DIR%\source.txt\" && type nul >\"%DATA_DIR%\move.flag\"" /f >nul reg add "%CBKG%\3_Paste" /ve /t REG_SZ /d "Paste" /f >nul reg add "%CBKG%\3_Paste\command" /ve /t REG_SZ /d "cmd.exe /c del \"%DATA_DIR%\contents.flag\" 2>nul && \"%DATA_DIR%\RoboAction.bat\" \"%%V\"" /f >nul reg add "%CBKG%\4_PasteContents" /ve /t REG_SZ /d "Paste Contents Only" /f >nul reg add "%CBKG%\4_PasteContents\command" /ve /t REG_SZ /d "cmd.exe /c type nul >\"%DATA_DIR%\contents.flag\" && \"%DATA_DIR%\RoboAction.bat\" \"%%V\"" /f >nul
:: Populate Class 2: Folders (Uses %%1, has all options) reg add "%CFLD%\1_Copy" /ve /t REG_SZ /d "Copy" /f >nul reg add "%CFLD%\1_Copy\command" /ve /t REG_SZ /d "cmd.exe /c echo %%1>\"%DATA_DIR%\source.txt\" && del \"%DATA_DIR%\move.flag\" 2>nul" /f >nul reg add "%CFLD%\2_Move" /ve /t REG_SZ /d "Move" /f >nul reg add "%CFLD%\2_Move\command" /ve /t REG_SZ /d "cmd.exe /c echo %%1>\"%DATA_DIR%\source.txt\" && type nul >\"%DATA_DIR%\move.flag\"" /f >nul reg add "%CFLD%\3_Paste" /ve /t REG_SZ /d "Paste" /f >nul reg add "%CFLD%\3_Paste\command" /ve /t REG_SZ /d "cmd.exe /c del \"%DATA_DIR%\contents.flag\" 2>nul && \"%DATA_DIR%\RoboAction.bat\" \"%%1\"" /f >nul reg add "%CFLD%\4_PasteContents" /ve /t REG_SZ /d "Paste Contents Only" /f >nul reg add "%CFLD%\4_PasteContents\command" /ve /t REG_SZ /d "cmd.exe /c type nul >\"%DATA_DIR%\contents.flag\" && \"%DATA_DIR%\RoboAction.bat\" \"%%1\"" /f >nul
:: Populate Class 3: Files (Uses %%1, no Paste Contents) reg add "%CFIL%\1_Copy" /ve /t REG_SZ /d "Copy" /f >nul reg add "%CFIL%\1_Copy\command" /ve /t REG_SZ /d "cmd.exe /c echo %%1>\"%DATA_DIR%\source.txt\" && del \"%DATA_DIR%\move.flag\" 2>nul" /f >nul reg add "%CFIL%\2_Move" /ve /t REG_SZ /d "Move" /f >nul reg add "%CFIL%\2_Move\command" /ve /t REG_SZ /d "cmd.exe /c echo %%1>\"%DATA_DIR%\source.txt\" && type nul >\"%DATA_DIR%\move.flag\"" /f >nul reg add "%CFIL%\3_Paste" /ve /t REG_SZ /d "Paste" /f >nul reg add "%CFIL%\3_Paste\command" /ve /t REG_SZ /d "cmd.exe /c del \"%DATA_DIR%\contents.flag\" 2>nul && \"%DATA_DIR%\RoboAction.bat\" \"%%1\"" /f >nul
:: --- 3. Link the Context Menus to the Classes --- set "LINK_BKG=%BKG%\RobocopySync" set "LINK_FLD=%FLD%\RobocopySync" set "LINK_FIL=%FIL%\RobocopySync"
for %%k in ("%LINK_BKG%" "%LINK_FLD%" "%LINK_FIL%") do ( reg add "%%~k" /v MUIVerb /t REG_SZ /d "Robocopy Tools" /f >nul reg add "%%~k" /v Icon /t REG_SZ /d "imageres.dll,-5302" /f >nul )
:: This tells Windows "Go look in this background class to find the drop-down list" reg add "%LINK_BKG%" /v ExtendedSubCommandsKey /t REG_SZ /d "RoboClass_Bkg" /f >nul reg add "%LINK_FLD%" /v ExtendedSubCommandsKey /t REG_SZ /d "RoboClass_Fld" /f >nul reg add "%LINK_FIL%" /v ExtendedSubCommandsKey /t REG_SZ /d "RoboClass_Fil" /f >nul
echo =================================================== echo Setup Complete! Cascading classes successfully mapped. echo ===================================================

